/// Statistics for external interrupts and clock interrupts.
///
/// This is a mapping from the interrupt number (exception number) to the count of
/// occurrences of that interrupt.
#[derive(Debug)]
pub struct TrapStats(SpinNoIrqLock<BTreeMap<usize, usize>>);

pub static TRAP_STATS: TrapStats = TrapStats(SpinNoIrqLock::new(BTreeMap::new()));

impl TrapStats {
    /// Increments the count for a specific trap by its trap number.
    pub fn inc(&self, trap: usize) {
        let mut stats = self.0.lock();
        *stats.entry(trap).or_insert(0) += 1;
    }

    /// Gets the current statistics as a mapping from trap numbers to counts.
    pub fn get_all(&self) -> BTreeMap<usize, usize> {
        let stats = self.0.lock();
        stats.clone()
    }
}

use systype::error::SysError;

use crate::{syscall::syscall, task::Task};

const NO_RESTART_SYSCALLS: &[usize] = &[22, 73, 137, 101];

pub async fn async_syscall(task: &Task) -> bool {
    if !task.is_syscall() {
        return false;
    }
    task.set_is_syscall(false);

    let mut cx = task.trap_context_mut();
    let syscall_no = cx.syscall_no();
    cx.sepc_forward();
    cx.save_last_user_ret_val();
    let sys_ret = syscall(syscall_no, cx.syscall_args()).await;
    cx = task.trap_context_mut();
    cx.set_user_ret_val(sys_ret);
    if (sys_ret == -(SysError::EINTR as isize) as usize) && (!NO_RESTART_SYSCALLS.contains(&syscall_no)) {
        log::info!("[async_syscall] EINTR, set interrupted to true");
        return true;
    }
    false
}

