};

impl AddrSpace {
    /// Maps a file into the process's virtual memory space.
    ///
    /// Creates a memory-mapped region for the given file, allowing it to be accessed
    /// as if it were in memory. The mapping can be either private or shared.
    ///
    /// # Returns
    /// On success, returns the actual virtual address where the file was mapped.
    /// On failure, returns a `SysError` indicating the reason.
    ///
    /// # Attention
    /// - If `va` is 0, the system automatically finds a suitable virtual address range
    pub fn map_file(
        &self,
        file: Option<Arc<dyn File>>,
        flags: MmapFlags,
        prot: MappingFlags,
        mut addr: VirtAddr,
        length: usize,
        offset: usize,
        seals: Option<MemfdSeals>,
    ) -> SysResult<usize> {
        if !flags.contains(MmapFlags::MAP_FIXED) {
            addr = self
                .find_vacant_memory(
                    addr,
                    length,
                    VirtAddr::new(MMAP_START),
                    VirtAddr::new(MMAP_END),
                )
                .ok_or(SysError::ENOMEM)?;
        }

        let length = (length + PAGE_SIZE - 1) & !(PAGE_SIZE - 1);
        let va_start = addr;
        let va_end = VirtAddr::new(addr.to_usize() + length);

        let vma_flags = match flags.intersection(MmapFlags::MAP_TYPE_MASK) {
            MmapFlags::MAP_PRIVATE => Ok(VmaFlags::PRIVATE),
            MmapFlags::MAP_SHARED => Ok(VmaFlags::SHARED),
            e => {
                log::error!("[map_file] invalid flag: {:?}", e);
                Err(SysError::EINVAL)
            }
        }?;

        let area = match file {
            Some(file) => VmArea::new_file_backed(
                va_start,
                va_end,
                vma_flags,
                prot,
                Arc::clone(&file),
                offset,
                length,
                seals,
            ),
            None => VmArea::new_anonymous(va_start, va_end, vma_flags, prot),
        };

        if flags.contains(MmapFlags::MAP_FIXED) {
            log::debug!(
                "[map_file] MmapFlags::MAP_FIXED remove area {:?} - {:?}",
                va_start,
                va_end
            );
            self.remove_mapping(va_start, length);
        }

        self.add_area(area)?;

        Ok(va_start.to_usize())
    }
}

//! Module for kernel heap allocator.
//!
//! Currently, we use the buddy system allocator for the kernel heap and use it to
//! allocate memory for all kernel objects that require dynamic memory allocation.

use core::{
    alloc::{GlobalAlloc, Layout},
    ptr::{self, NonNull},
};

use buddy_system_allocator as buddy;

use config::mm::KERNEL_HEAP_SIZE;
use mutex::SpinNoIrqLock;

use crate::address::VirtAddr;

/// A heap allocator protected by a spin lock.
struct NoIrqLockedHeap<const ORDER: usize>(SpinNoIrqLock<buddy::Heap<ORDER>>);

impl<const ORDER: usize> NoIrqLockedHeap<ORDER> {
    /// Creates a new heap allocator.
    const fn new() -> Self {
        Self(SpinNoIrqLock::new(buddy::Heap::empty()))
    }

    /// Initializes the heap allocator with the given start address and size.
    ///
    /// # Safety
    /// - This function should be called only once.
    /// - The caller should ensure that the heap is not being referenced by any other thread.
    unsafe fn init(&self, start_addr: usize, size: usize) {
        unsafe {
            self.0.lock().init(start_addr, size);
        }
    }
}

unsafe impl GlobalAlloc for NoIrqLockedHeap<32> {
    unsafe fn alloc(&self, layout: Layout) -> *mut u8 {
        self.0
            .lock()
            .alloc(layout)
            .ok()
            .map_or(ptr::null_mut(), |allocation| allocation.as_ptr())
    }

    unsafe fn dealloc(&self, ptr: *mut u8, layout: Layout) {
        unsafe { self.0.lock().dealloc(NonNull::new_unchecked(ptr), layout) }
    }
}

#[repr(align(4096))]
struct HeapMemory([u8; KERNEL_HEAP_SIZE]);

/// Memory space for the kernel heap.
static mut HEAP_MEMORY: HeapMemory = HeapMemory([0; KERNEL_HEAP_SIZE]);

/// The global heap allocator for the kernel.
#[global_allocator]
static HEAP_ALLOCATOR: NoIrqLockedHeap<32> = NoIrqLockedHeap::new();

#[alloc_error_handler]
fn alloc_error_handler(layout: Layout) -> ! {
    simdebug::stop0();
    panic!("heap allocation error, layout = {:?}", layout)
}

/// Initializes the kernel heap allocator.
///
/// # Safety
/// This function should be called only once before making any heap allocations.
pub unsafe fn init_heap_allocator() {
    let start_addr = unsafe {
        // SAFETY: we are the only one using the heap
        #[allow(static_mut_refs)]
        VirtAddr::new(HEAP_MEMORY.0.as_ptr() as usize).to_usize()
    };

    unsafe {
        HEAP_ALLOCATOR.init(start_addr, KERNEL_HEAP_SIZE);
    }

    log::info!(
        "heap memory: {:#x} - {:#x}",
        start_addr,
        start_addr + KERNEL_HEAP_SIZE
    );
}

