/// Read a proc pseudo-file honoring the caller offset (supports partial reads + EOF).
pub(crate) fn read_pseudo_file(content: &str, buf: &mut [u8], offset: usize) -> SysResult<usize> {
    let data = content.as_bytes();
    if offset >= data.len() {
        return Ok(0);
    }
    let nbytes = cmp::min(buf.len(), data.len() - offset);
    buf[..nbytes].copy_from_slice(&data[offset..offset + nbytes]);
    Ok(nbytes)
}

